function base64UrlEncode(buffer) {
  return buffer
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

function base64UrlDecode(str) {
  str = str.replace(/-/g, '+').replace(/_/g, '/');
  const padding = 4 - (str.length % 4);
  if (padding !== 4) {
    str += '='.repeat(padding);
  }
  return Buffer.from(str, 'base64');
}

// Supported algorithms and their corresponding HMAC/RSA variants
const ALLOWED_ALGORITHMS = new Set(['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512']);

const HMAC_ALGORITHMS = {
  HS256: 'sha256',
  HS384: 'sha384',
  HS512: 'sha512',
};

const RSA_ALGORITHMS = {
  RS256: 'SHA256',
  RS384: 'SHA384',
  RS512: 'SHA512',
};

function signJwt(payload, secret, options = {}) {
  const algorithm = options.algorithm || 'HS256';

  if (!ALLOWED_ALGORITHMS.has(algorithm)) {
    throw new Error(`Unsupported algorithm: ${algorithm}`);
  }

  const now = Math.floor(Date.now() / 1000);

  const fullPayload = {
    ...payload,
    iat: payload.iat || now,
  };

  if (options.expiresIn) {
    fullPayload.exp = now + options.expiresIn;
  }

  if (options.issuer) {
    fullPayload.iss = options.issuer;
  }

  if (options.audience) {
    fullPayload.aud = options.audience;
  }

  if (options.jwtId) {
    fullPayload.jti = options.jwtId;
  }

  const header = {
    alg: algorithm,
    typ: 'JWT',
  };

  const encodedHeader = base64UrlEncode(Buffer.from(JSON.stringify(header)));
  const encodedPayload = base64UrlEncode(Buffer.from(JSON.stringify(fullPayload)));
  const signingInput = `${encodedHeader}.${encodedPayload}`;

  let signature;

  if (HMAC_ALGORITHMS[algorithm]) {
    const hmac = crypto.createHmac(HMAC_ALGORITHMS[algorithm], secret);
    hmac.update(signingInput);
    signature = base64UrlEncode(hmac.digest());
  } else if (RSA_ALGORITHMS[algorithm]) {
    const sign = crypto.createSign(RSA_ALGORITHMS[algorithm]);
    sign.update(signingInput);
    signature = base64UrlEncode(sign.sign(secret));
  }

  return `${signingInput}.${signature}`;
}

function verifyJwt(token, secret, options = {}) {
  if (!token || typeof token !== 'string') {
    throw new JwtError('Token must be a non-empty string', 'INVALID_TOKEN');
  }

  const parts = token.split('.');
  if (parts.length !== 3) {
    throw new JwtError('Token must have 3 parts', 'MALFORMED_TOKEN');
  }

  const [encodedHeader, encodedPayload, encodedSignature] = parts;

  // Decode and validate header
  let header;
  try {
    header = JSON.parse(base64UrlDecode(encodedHeader).toString());
  } catch (e) {
    throw new JwtError('Invalid token header', 'MALFORMED_TOKEN');
  }

  // CRITICAL: Prevent "alg: none" attack
  if (!header.alg || header.alg.toLowerCase() === 'none') {
    throw new JwtError('Algorithm "none" is not allowed', 'INSECURE_ALGORITHM');
  }

  // CRITICAL: Enforce expected algorithm to prevent algorithm confusion attacks
  const expectedAlgorithm = options.algorithm || 'HS256';
  if (header.alg !== expectedAlgorithm) {
    throw new JwtError(
      `Algorithm mismatch. Expected ${expectedAlgorithm}, got ${header.alg}`,
      'ALGORITHM_MISMATCH'
    );
  }

  if (!ALLOWED_ALGORITHMS.has(header.alg)) {
    throw new JwtError(`Unsupported algorithm: ${header.alg}`, 'UNSUPPORTED_ALGORITHM');
  }

  // Verify signature
  const signingInput = `${encodedHeader}.${encodedPayload}`;
  let signatureValid = false;

  if (HMAC_ALGORITHMS[header.alg]) {
    const hmac = crypto.createHmac(HMAC_ALGORITHMS[header.alg], secret);
    hmac.update(signingInput);
    const expectedSignature = base64UrlEncode(hmac.digest());

    // Timing-safe comparison to prevent timing attacks
    const sigBuffer = Buffer.from(encodedSignature);
    const expectedBuffer = Buffer.from(expectedSignature);

    if (sigBuffer.length === expectedBuffer.length) {
      signatureValid = crypto.timingSafeEqual(sigBuffer, expectedBuffer);
    }
  } else if (RSA_ALGORITHMS[header.alg]) {
    const verify = crypto.createVerify(RSA_ALGORITHMS[header.alg]);
    verify.update(signingInput);
    signatureValid = verify.verify(secret, base64UrlDecode(encodedSignature));
  }

  if (!signatureValid) {
    throw new JwtError('Invalid signature', 'INVALID_SIGNATURE');
  }

  // Decode payload
  let payload;
  try {
    payload = JSON.parse(base64UrlDecode(encodedPayload).toString());
  } catch (e) {
    throw new JwtError('Invalid token payload', 'MALFORMED_TOKEN');
  }

  const now = Math.floor(Date.now() / 1000);
  const clockTolerance = options.clockTolerance || 0;

  // Validate expiration
  if (payload.exp !== undefined) {
    if (typeof payload.exp !== 'number') {
      throw new JwtError('Invalid exp claim', 'INVALID_CLAIM');
    }
    if (now > payload.exp + clockTolerance) {
      throw new JwtError('Token has expired', 'TOKEN_EXPIRED');
    }
  } else if (options.requireExp !== false) {
    // By default, require expiration to prevent indefinitely valid tokens
    throw new JwtError('Token missing required exp claim', 'MISSING_CLAIM');
  }

  // Validate not-before
  if (payload.nbf !== undefined) {
    if (typeof payload.nbf !== 'number') {
      throw new JwtError('Invalid nbf claim', 'INVALID_CLAIM');
    }
    if (now < payload.nbf - clockTolerance) {
      throw new JwtError('Token not yet valid', 'TOKEN_NOT_ACTIVE');
    }
  }

  // Validate issuer
  if (options.issuer) {
    const validIssuers = Array.isArray(options.issuer) ? options.issuer : [options.issuer];
    if (!validIssuers.includes(payload.iss)) {
      throw new JwtError('Invalid issuer', 'INVALID_ISSUER');
    }
  }

  // Validate audience
  if (options.audience) {
    const validAudiences = Array.isArray(options.audience) ? options.audience : [options.audience];
    const tokenAudiences = Array.isArray(payload.aud) ? payload.aud : [payload.aud];
    const hasValidAudience = tokenAudiences.some((aud) => validAudiences.includes(aud));
    if (!hasValidAudience) {
      throw new JwtError('Invalid audience', 'INVALID_AUDIENCE');
    }
  }

  return { header, payload };
}

