// ============================================================
// In-Memory Token Version Cache (for high-performance revocation)
// ============================================================

/**
 * Instead of checking a blocklist on every request, we use a "token version"
 * strategy. Each user has a token version stored in the DB. When we need to
 * revoke all tokens for a user (password change, logout-all), we increment
 * the version. The JWT contains the version at issuance time.
 *
 * We cache user token versions in memory with a short TTL so we only hit
 * the database periodically, not on every request.
 */
class TokenVersionCache {
  constructor(options = {}) {
    this.cache = new Map();
    this.ttl = options.ttl || 60000; // 1 minute default TTL
    this.maxSize = options.maxSize || 100000;
    this.fetchVersion = options.fetchVersion; // async function(userId) => version number

    // Periodic cleanup of expired entries
    this.cleanupInterval = setInterval(() => {
      this._cleanup();
    }, options.cleanupInterval || 300000); // 5 minutes

    // Allow garbage collection of the interval
    if (this.cleanupInterval.unref) {
      this.cleanupInterval.unref();
    }
  }

  async getVersion(userId) {
    const entry = this.cache.get(userId);
    const now = Date.now();

    if (entry && now - entry.timestamp < this.ttl) {
      return entry.version;
    }

    // Cache miss or expired - fetch from database
    if (this.fetchVersion) {
      try {
        const version = await this.fetchVersion(userId);
        this._set(userId, version);
        return version;
      } catch (err) {
        // If we can't reach the DB, use stale cache if available
        if (entry) {
          return entry.version;
        }
        throw err;
      }
    }

    return null; // No fetch function configured, skip version check
  }

  invalidate(userId) {
    this.cache.delete(userId);
  }

  _set(userId, version) {
    // Evict oldest entries if cache is full
    if (this.cache.size >= this.maxSize) {
      const firstKey = this.cache.keys().next().value;
      this.cache.delete(firstKey);
    }
    this.cache.set(userId, { version, timestamp: Date.now() });
  }

  _cleanup() {
    const now = Date.now();
    for (const [key, entry] of this.cache) {
      if (now - entry.timestamp > this.ttl * 2) {
        this.cache.delete(key);
      }
    }
  }

  destroy() {
    clearInterval(this.cleanupInterval);
    this.cache.clear();
  }
}

